```

### Step 3: Game Logic

```python
def is_valid_move(board, start, end):
    # Check if the move is within bounds and empty
    if not (0 <= start[0] < 8 and 0 <= start[1] < 8 and 0 <= end[0] < 8 and 0 <= end[1] < 8):
        return False

    if board[start[0]][start[1]] == " " or board[end[0]][end[1]] != " ":
        return False

    # Check the move distance
    row_diff = abs(start[0] - end[0])
    col_diff = abs(start[1] - end[1])

    if (board[start[0]][start[1]].islower() and row_diff != 1 or board[start[0]][start[1]].isupper() and row_diff > 2) or col_diff != 1:
        return False

    # Check capturing
    if row_diff == 2:
        mid_row = (start[0] + end[0]) // 2
        mid_col = (start[1] + end[1]) // 2
        if board[mid_row][mid_col].islower() and board[end[0]][end[1]].isupper():
            return True
        elif board[mid_row][mid_col].isupper() and board[end[0]][end[1]].islower():
            return True

    return True

def move_piece(board, start, end):
    piece = board[start[0]][start[1]]
    board[start[0]][start[1]] = " "
    board[end[0]][end[1]] = piece
```

### Step 4: User Input

```python
def get_move():
    while True:
        move = input("Enter your move (e.g., A1-B2): ").strip().upper()
        if len(move) == 5 and move[2] == '-':
            start_col, start_row = ord(move[0]) - ord('A'), int(move[1]) - 1
            end_col, end_row = ord(move[3]) - ord('A'), int(move[4]) - 1
            return (start_row, start_col), (end_row, end_col)
        else:
            print("Invalid move format. Please try again.")
```

### Step 5: Game Loop

```python
def check_win(board):
    black_pieces = sum(row.count('b') for row in board)
    white_pieces = sum(row.count('B') for row in board)

    if black_pieces == 0:
        return "White wins!"
    elif white_pieces == 0:
        return "Black wins!"
    else:
        return None

def main():
    board = init_board()
    current_player = 'b'

    while True:
        print_board(board)
        start, end = get_move()

        if is_valid_move(board, start, end):
            move_piece(board, start, end)
            current_player = 'w' if current_player == 'b' else 'b'
        else:
            print("Invalid move. Try again.")

        winner = check_win(board)
        if winner:
            print_board(board)
            print(winner)
            break

if __name__ == "__main__":
    main()
```

